package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        // Use reflection to set the private final field 'nullString' to null
        java.lang.reflect.Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // Create a new CSVFormat instance with nullString set to null via reflection
        CSVFormat newFormat = CSVFormat.DEFAULT;
        nullStringField.set(newFormat, null);

        csvFormat = newFormat;

        assertFalse(csvFormat.isNullStringSet());
    }

    @Test
    void testIsNullStringSet_whenNullStringIsNotNull() throws Exception {
        // Use withNullString method which returns a new CSVFormat instance
        csvFormat = csvFormat.withNullString("NULL");
        assertTrue(csvFormat.isNullStringSet());
    }
}
